package com.csu.carenest.careadmin.customer;
import com.csu.carenest.careadmin.common.ApiResponse; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/v1/customer-service/tickets") public class CustomerServiceTicketController {private final CustomerServiceTicketService service;public CustomerServiceTicketController(CustomerServiceTicketService s){service=s;}
 @GetMapping public ApiResponse<CustomerServiceTicketDtos.PageResult<CustomerServiceTicketDtos.TicketItem>> list(@RequestHeader("Authorization")String a,@RequestParam(required=false)String status,@RequestParam(required=false)String priority,@RequestParam(required=false)String keyword,@RequestParam(defaultValue="1")int page,@RequestParam(defaultValue="20")int size){return ApiResponse.success(service.list(a,status,priority,keyword,page,size));}
 @GetMapping("/{id}") public ApiResponse<CustomerServiceTicketDtos.TicketDetail> detail(@RequestHeader("Authorization")String a,@PathVariable String id){return ApiResponse.success(service.detail(a,id));}
 @PostMapping("/{id}/status") public ApiResponse<CustomerServiceTicketDtos.TicketItem> status(@RequestHeader("Authorization")String a,@PathVariable String id,@RequestBody CustomerServiceTicketDtos.StatusRequest r){return ApiResponse.success(service.status(a,id,r));}
 @PostMapping("/{id}/messages") public ApiResponse<CustomerServiceTicketDtos.TicketMessageItem> message(@RequestHeader("Authorization")String a,@PathVariable String id,@RequestBody CustomerServiceTicketDtos.MessageRequest r){return ApiResponse.success(service.message(a,id,r));}}
